// Collect all pages returned by the paginating HTTP Request node,
// filter to Sent email campaigns within the last 90 days,
// and extract the send hour (UTC) and segment key from each.

const allItems = $input.all();
const cutoffMs = Date.now() - 90 * 24 * 60 * 60 * 1000;

const campaigns = [];

for (const item of allItems) {
  const page = item.json;

  let parsed = page;
  if (typeof page.data === 'string') {
    try { parsed = JSON.parse(page.data); } catch (e) { parsed = page; }
  }

  let rows;
  if (Array.isArray(parsed)) {
    rows = parsed;
  } else if (Array.isArray(parsed.data)) {
    rows = parsed.data;
  } else {
    rows = [];
  }

  for (const row of rows) {
    const attrs = row.attributes || {};
    const status = (attrs.status || '').toLowerCase();
    if (status !== 'sent') continue;

    const dateStr = attrs.scheduled_at || attrs.send_strategy?.options_static?.datetime || '';
    const sentDate = dateStr ? new Date(dateStr) : null;
    if (sentDate && !isNaN(sentDate.getTime()) && sentDate.getTime() < cutoffMs) continue;
    const sendHour = (sentDate && !isNaN(sentDate.getTime())) ? sentDate.getUTCHours() : 9;

    const audiences = attrs.audiences || {};
    const listIds = audiences.included || [];
    const segmentKey = listIds.length > 0 ? listIds.join(',') : 'all';

    campaigns.push({id: row.id, name: attrs.name || 'Unknown', send_hour: sendHour, segment_key: segmentKey, scheduled_at: dateStr});
  }
}

if (campaigns.length === 0) {
  const firstPage = allItems[0]?.json || {};
  throw new Error(`No sent campaigns found after parsing. Items received: ${allItems.length}. First item keys: ${Object.keys(firstPage).join(', ')}. data type: ${typeof firstPage.data}`);
}

return [{ json: { campaigns, total: campaigns.length } }];

// Join campaign metadata with open-rate stats, aggregate into per-segment-per-hour buckets.

const MIN_CAMPAIGNS = 3;

const flattenedData = $('Flatten Campaigns').first().json;
const campaigns = flattenedData.campaigns || [];

let listsRaw = $('Fetch Lists').first().json;
if (typeof listsRaw.data === 'string') {
  try { listsRaw = JSON.parse(listsRaw.data); } catch(e) {}
}
const listItems = Array.isArray(listsRaw) ? listsRaw : (Array.isArray(listsRaw?.data) ? listsRaw.data : []);
const nameMap = {};
for (const l of listItems) {
  if (l.id && l.attributes?.name) nameMap[l.id] = l.attributes.name;
}

let statsRaw = $input.first().json;
if (typeof statsRaw.data === 'string') {
  try { statsRaw = JSON.parse(statsRaw.data); } catch (e) {}
}
const results = (statsRaw?.data?.attributes?.results || statsRaw?.attributes?.results || statsRaw?.results || []);

const statsMap = {};
for (const r of results) {
  const campaignId = r.campaign_id || (r.groupings && r.groupings.campaign_id) || r.id;
  if (!campaignId) continue;
  const stats = r.statistics || {};
  statsMap[campaignId] = {open_rate: parseFloat(stats.open_rate ?? 0), click_rate: parseFloat(stats.click_rate ?? 0)};
}

const buckets = {};
for (const c of campaigns) {
  const stats = statsMap[c.id];
  if (!stats) continue;
  const key = `${c.segment_key}__${c.send_hour}`;
  if (!buckets[key]) {
    buckets[key] = {segment_key: c.segment_key, send_hour: c.send_hour, label: `${String(c.send_hour).padStart(2, '0')}:00 UTC`, total_open_rate: 0, total_click_rate: 0, count: 0};
  }
  buckets[key].total_open_rate += stats.open_rate;
  buckets[key].total_click_rate += stats.click_rate;
  buckets[key].count += 1;
}

const allBuckets = Object.values(buckets).map(b => ({...b, avg_open_rate: b.count > 0 ? b.total_open_rate / b.count : 0, avg_click_rate: b.count > 0 ? b.total_click_rate / b.count : 0}));

const qualified = allBuckets.filter(b => b.count >= MIN_CAMPAIGNS);
const warning = qualified.length === 0 ? `No time slots had ${MIN_CAMPAIGNS}+ campaigns yet. Showing all available data instead.` : null;
const outputBuckets = qualified.length > 0 ? qualified : allBuckets;

return [{json: {buckets: outputBuckets, total_campaigns_analysed: campaigns.length, total_with_stats: results.length, warning, nameMap}}];

const { buckets, total_campaigns_analysed, total_with_stats, warning, nameMap = {} } = $input.first().json;

function resolveSegmentLabel(segId) {
  if (!segId || segId === 'all') return 'All Subscribers';
  return segId.split(',').map(id => nameMap[id] || id).join(' + ');
}

const bySegment = {};
for (const b of buckets) {
  const seg = b.segment_key || 'all';
  if (!bySegment[seg]) bySegment[seg] = [];
  bySegment[seg].push(b);
}

for (const slots of Object.values(bySegment)) {
  slots.sort((a, b) => b.avg_open_rate - a.avg_open_rate);
}

const reportDate = new Date().toLocaleDateString('en-US', {weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'});
const medals = ['🥇', '🥈', '🥉'];
const rankColors = [{bg: '#fff8e1', border: '#f5a623'}, {bg: '#f5f5f5', border: '#9b9b9b'}, {bg: '#fdf6ee', border: '#c97c3a'}];

const segmentSections = Object.entries(bySegment)
  .sort(([, slotsA], [, slotsB]) => (slotsB[0]?.avg_open_rate || 0) - (slotsA[0]?.avg_open_rate || 0))
  .map(([segId, slots]) => {
    const segLabel = resolveSegmentLabel(segId);
    const rows = slots.slice(0, 5).map((slot, i) => {
      const medal = medals[i] || `${i + 1}.`;
      const openRateStr = (slot.avg_open_rate * 100).toFixed(1);
      const clickRateStr = (slot.avg_click_rate * 100).toFixed(1);
      const color = rankColors[i] || {bg: '#fafafa', border: '#ddd'};
      return `<tr><td style="padding:0 0 6px 0;"><div style="padding:12px 16px;background:${color.bg};border-left:4px solid ${color.border};border-radius:4px;"><span style="font-size:16px;font-weight:bold;">${medal} ${slot.label}</span><span style="color:#555;font-size:14px;"> &mdash; <strong>${openRateStr}%</strong> open rate &nbsp;&bull;&nbsp; <strong>${clickRateStr}%</strong> click rate &nbsp;&bull;&nbsp; ${slot.count} campaign${slot.count !== 1 ? 's' : ''}</span></div></td></tr>`;
    }).join('');
    return `<h2 style="color:#333;border-bottom:2px solid #eee;padding-bottom:8px;margin-top:28px;">${segLabel}</h2><table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse;">${rows}</table>`;
  }).join('');

const warningHtml = warning ? `<div style="background:#fff3cd;border:1px solid #ffc107;padding:12px 16px;border-radius:4px;margin-bottom:20px;font-size:14px;">⚠️ ${warning}</div>` : '';
const noDataHtml = buckets.length === 0 ? '<p style="color:#666;">No data available yet. Campaigns will appear here after they are sent.</p>' : '';

const html = `<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head><body style="font-family:Arial,Helvetica,sans-serif;max-width:680px;margin:0 auto;padding:24px;color:#1a1a1a;"><table width="100%" cellpadding="0" cellspacing="0" style="background:#4f46e5;border-radius:8px;margin-bottom:24px;"><tr><td style="padding:20px 24px;"><h1 style="margin:0;color:#fff;font-size:22px;">📊 Campaign Send-Time Report</h1><p style="margin:4px 0 0;color:#c7d2fe;font-size:14px;">Week of ${reportDate}</p></td></tr></table><p style="color:#555;font-size:14px;margin-bottom:6px;"><strong>${total_campaigns_analysed}</strong> campaigns analysed &nbsp;&bull;&nbsp; <strong>${total_with_stats}</strong> with open-rate data &nbsp;&bull;&nbsp; Last 90 days &nbsp;&bull;&nbsp; Times shown in UTC</p>${warningHtml}${noDataHtml}${segmentSections}<hr style="border:none;border-top:1px solid #eee;margin:32px 0 16px;"><p style="color:#999;font-size:12px;">Generated automatically every Monday by your n8n Campaign Send-Time Optimizer.<br>Tip: if you see audience IDs instead of names, map them in the Aggregate by Hour node.</p></body></html>`;
const subject = `📊 Send-Time Report — ${reportDate}`;
return [{ json: { subject, html, reportDate } }];
